# name: low_periodicity_b_choice_rate
# description: Mean chose_left when periodicity_b <= 0.667 (lowest tercile, B has low periodic structure); tests whether the model — which ignores periodicity — correctly predicts the near-ceiling left-choice rate observed for these trials.
def test_statistic(df):
    sub = df[df["periodicity_b"] <= 0.667]
    if len(sub) == 0:
        return float("nan")
    return float(sub["chose_left"].mean())

# name: periodicity_b_choice_correlation
# description: Pearson correlation between periodicity_b and chose_left across all trials; tests whether a feature entirely absent from the model (periodicity of sequence B) independently predicts human choice direction.
def test_statistic(df):
    r = np.corrcoef(df["periodicity_b"].values, df["chose_left"].values)[0, 1]
    return float(r)

# name: lag1_choice_autocorrelation
# description: Mean within-participant lag-1 Pearson autocorrelation of chose_left (trials ordered by trial_index); tests for response-alternation sequential dependence that the model's trial-independence assumption cannot produce.
def test_statistic(df):
    autocorrs = []
    for pid, grp in df.groupby("participant_id"):
        y = grp.sort_values("trial_index")["chose_left"].values
        if len(y) < 3:
            continue
        r = np.corrcoef(y[:-1], y[1:])[0, 1]
        if not math.isnan(r):
            autocorrs.append(r)
    if not autocorrs:
        return float("nan")
    return float(np.mean(autocorrs))

# name: na2_alts_b_choice_slope
# description: OLS regression slope of chose_left on alts_b restricted to n_a = 2 trials (the dominant trial type, 81% of data); tests whether the model correctly reproduces the steepness of the alternation-count effect on choice within the most common stimulus condition.
def test_statistic(df):
    sub = df[df["n_a"] == 2]
    if len(sub) < 3:
        return float("nan")
    x = sub["alts_b"].values.astype(float)
    y = sub["chose_left"].values.astype(float)
    slope = np.polyfit(x, y, 1)[0]
    return float(slope)

# name: within_trial_choice_variance
# description: Mean of the within-trial sample variance of chose_left (computed as k*(n-k)/(n*(n-1)) per trial where k = sum chose_left and n = participants per trial), averaged across the 32 unique trials; detects overdispersion relative to binomial predictions from individual differences the model cannot represent.
def test_statistic(df):
    variances = []
    for _, grp in df.groupby("trial_index"):
        k = grp["chose_left"].sum()
        n = len(grp)
        if n < 2:
            continue
        v = k * (n - k) / (n * (n - 1))
        variances.append(v)
    if not variances:
        return float("nan")
    return float(np.mean(variances))

# name: alts_b5_choice_rate
# description: Mean chose_left when alts_b = 5 (moderately-high alternation in B, the critical transition zone between majority A-choice at alts_b = 4 and full B-choice at alts_b = 7); tests model calibration at the steepest part of the alternation-rate psychometric function.
def test_statistic(df):
    sub = df[df["alts_b"] == 5]
    if len(sub) == 0:
        return float("nan")
    return float(sub["chose_left"].mean())

# name: na_length_choice_rate_gap
# description: Mean chose_left for n_a = 2 (short A) minus mean chose_left for n_a >= 4 (longer A); tests whether the model captures the full magnitude of the sequence-length contrast in left-choice rates driven by differences in A's apparent non-randomness.
def test_statistic(df):
    short = df[df["n_a"] == 2]["chose_left"].mean()
    long_ = df[df["n_a"] >= 4]["chose_left"].mean()
    return float(short - long_)

# name: na4_choice_rate
# description: Mean chose_left restricted to trials where n_a = 4 (medium-length A sequences with low alternation); tests whether the model correctly predicts near-0 left-choice for these streaky A sequences that the Bayesian score may mis-score as fair-coin diagnostic.
def test_statistic(df):
    sub = df[df["n_a"] == 4]
    if len(sub) == 0:
        return float("nan")
    return float(sub["chose_left"].mean())
